const variants = {
  enter: (direction) => ({
    y: direction > 0 ? "100%" : "-100%",
  }),
  center: { y: "0%" },
  exit: (direction) => ({
    y: direction > 0 ? "-100%" : "100%",
  }),
};

<AnimatePresence custom={direction}>
  <motion.div
    key={index}
    custom={direction}
    variants={variants}
    initial="enter"
    animate="center"
    exit="exit"
    transition={{ duration: 0.7, ease: [0.76, 0, 0.24, 1] }}
  >
    {/* Content */}
  </motion.div>
</AnimatePresence>
